INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("もうすぐ、みなさまに\nお会いできるのですね。\n胸が高鳴ってしまいます……\n", 1, "リリ", 125801, 2, 1, 40011, 0, 321, 1, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("初めまして、クリアです♪\nみなさんと一緒に冒険するの\nとっても楽しみにしてます", 2, "クリア", 126001, 2, 1, 40011, 0, 322, 1, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("んーと。\nこれ、あげる。\nはい", 3, "プレシア", 126101, 2, 1, 40011, 0, 323, 1, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("あらためまして……\n【アルターメイデン】の\nギルドマスター、リリと申します", 4, "リリ", 125801, 2, 1, 40011, 0, 324, 2, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("こんにちは、お兄さん♪\n【アルターメイデン】の\nクリアです", 5, "クリア", 126001, 2, 1, 40011, 0, 325, 2, 24001);
INSERT INTO `v1_cbca4c68900b058be7859053fc86c90e111abe8bdc159a63d8dec7a6f4d760ee` VALUES ("お兄。\nきてくれて、うれしい", 6, "プレシア", 126101, 2, 1, 40011, 0, 326, 2, 24001);
